// Worked focus: cmem-partial-initialization-state — Represent which subresources are initialized so cleanup is valid after every acquisition point.
/* Evidence: cmem-worked-cmem-cleanup-error-paths-3 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 4597; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int worked_cmem_cleanup_error_paths_3(int fail_stage, int released[3]) {
  int acquired = 0;
  int index;
  for (index = 0; index < 3; ++index) {
    if (fail_stage == index) break;
    acquired += 1;
  }
  while (acquired > 0) {
    acquired -= 1;
    released[acquired] = 4 + acquired;
  }
  return fail_stage < 3 ? 0 : 1;
}

int main(void) {
  int released[3] = { 0, 0, 0 };
  int completed = worked_cmem_cleanup_error_paths_3(3, released);
  int invariant = completed && released[2] == 6 && released[0] == 4;
  printf("cleanup first=%d last=%d invariant=%d\n", released[2], released[0], invariant);
  return invariant ? 0 : 1;
}

